import type { Metadata } from "next";
import RailOperations from "./RailOperations";

export const metadata: Metadata = {
  title: "運転指令（運行管理） — 彩央本線 | ぐんじょう 鉄道",
  description:
    "鉄道の運転指令員（運行管理）向け管制画面。彩央本線の在線列車を一覧（列車番号・種別・行先・現在位置・定刻/実績・遅延分・状態・編成/運用）で監視し、ダイヤ乱れ・指令アラート（抑止/遅延拡大/運休/折返し変更/接続調整/設備支障）を重大度順のワークリストでトリアージ。運行図表（スジ／時間×距離）で遅延波及を把握し、順序変更・運休・区間運休・折返し変更の運転整理を発令・記録する。車両運用・折返しの行路、列車詳細ドリルインを備えた管制室向け画面。",
};

export default function RailOperationsPage() {
  return <RailOperations />;
}

// 鉄道運転指令（運行管理）画面 — ドメインデータ
// 架空の「彩央本線（さおうほんせん）」を題材にした運転指令員向けの運行状況。
// 時刻はすべて当日 07:xx〜08:xx の朝ラッシュ帯を想定（"HH:MM"）。

export type TrainStatus =
  | "normal" // 平常
  | "delayed" // 遅延（〜4分）
  | "heavyDelay" // 大幅遅延（5分〜）
  | "suspended" // 抑止（停止）中
  | "cancelled" // 運休
  | "deadhead"; // 回送

export type TrainKind = "local" | "rapid" | "express" | "deadhead";

export interface Train {
  /** 列車番号 (例: 1234M / 5021A) */
  no: string;
  /** 種別 */
  kind: TrainKind;
  /** 行先 */
  destination: string;
  /** 上り / 下り */
  direction: "up" | "down";
  /** 現在位置（駅名 または 「A駅〜B駅」） */
  position: string;
  /** 直近通過/在線の基準駅での定刻 "HH:MM" */
  scheduled: string;
  /** 同・実績 "HH:MM"（未到達なら推定） */
  actual: string;
  /** 遅延（分）＋遅れ / −早発 */
  delayMin: number;
  status: TrainStatus;
  /** 編成（両数） */
  cars: number;
  /** 運用番号 */
  duty: string;
  /** 乗務員行路 */
  crew: string;
  /** 遅延理由（あれば） */
  reason?: string;
  /** 次の折返し駅・番線（terminal到着列車のみ） */
  turnback?: string;
}

export const KIND_LABEL: Record<TrainKind, string> = {
  local: "普通",
  rapid: "快速",
  express: "特急",
  deadhead: "回送",
};

// 彩央本線の駅シーケンス（下り方向: 彩央 → 桜ヶ丘）。運行図表の縦軸に使う。
export interface Station {
  /** 駅コード */
  code: string;
  name: string;
  /** 起点（彩央）からの営業キロ。運行図表の縦軸スケールに使用。 */
  km: number;
