// ── サマリ指標（StatGroup 用） ───────────────────────────────────────
export const summary = {
  running: trains.filter((t) => t.status !== "cancelled").length,
  delayed: trains.filter((t) => t.status === "delayed" || t.status === "heavyDelay").length,
  cancelled: trains.filter((t) => t.status === "cancelled").length,
  suspended: trains.filter((t) => t.status === "suspended").length,
  maxDelay: Math.max(...trains.map((t) => t.delayMin)),
  onTimeRate: Math.round(
    (trains.filter((t) => t.status === "normal" || t.status === "deadhead").length /
      trains.length) *
