import { Badge } from "@gunjo/ui";
import type { TrainStatus, AlertSeverity } from "./data";

type BadgeVariant = "secondary" | "info" | "success" | "destructive" | "warning";

export const TRAIN_STATUS_CONFIG: Record<
  TrainStatus,
  { label: string; variant: BadgeVariant; icon: typeof IconCircleCheckFilled }
