  suspended: { label: "抑止", variant: "destructive", icon: IconHandStop },
  cancelled: { label: "運休", variant: "secondary", icon: IconBan },
  deadhead: { label: "回送", variant: "info", icon: IconArrowsExchange },
};

/** 列車状態バッジ（アイコン付き＝色だけに依存しない）。 */
export function TrainStatusBadge({ status }: { status: TrainStatus }) {
  const c = TRAIN_STATUS_CONFIG[status];
  const Glyph = c.icon;
  return (
    <Badge variant={c.variant} icon={<Glyph />}>
      {c.label}
    </Badge>
  );
}

