  STATIONS,
  KIND_LABEL,
  stringlineWindow,
  stringlineTrains,
  type StringlineTrain,
  type TrainKind,
} from "./data";

function hmToMin(t: string): number {
  const [h, m] = t.split(":").map(Number);
  return h * 60 + m;
}

const KIND_COLOR: Record<TrainKind, string> = {
  express: "var(--destructive, #dc2626)",
  rapid: "var(--warning, #d97706)",
  local: "var(--info, #2563eb)",
  deadhead: "var(--muted-foreground, #6b7280)",
};

// レイアウト（viewBox 座標）。レスポンシブは viewBox + preserveAspectRatio。
const PAD_L = 56; // 駅名ラベル分の左余白
const PAD_R = 16;
const PAD_T = 8;
const PAD_B = 28; // 時刻軸
const W = 760;
const H = 360;
const PLOT_W = W - PAD_L - PAD_R;
const PLOT_H = H - PAD_T - PAD_B;

const KM_MIN = STATIONS[0].km;
const KM_MAX = STATIONS[STATIONS.length - 1].km;
const T_MIN = hmToMin(stringlineWindow.start);
const T_MAX = hmToMin(stringlineWindow.end);

function xOf(min: number): number {
  return PAD_L + ((min - T_MIN) / (T_MAX - T_MIN)) * PLOT_W;
}
function yOf(km: number): number {
  return PAD_T + ((km - KM_MIN) / (KM_MAX - KM_MIN)) * PLOT_H;
}

function kmOfStation(name: string): number | null {
  const s = STATIONS.find((st) => st.name === name);
  return s ? s.km : null;
}

function pathFor(train: StringlineTrain, useActual: boolean): string {
  const pts: string[] = [];
  for (const p of train.points) {
    const t = useActual ? p.actual : p.scheduled;
    if (!t) continue;
    const km = kmOfStation(p.station);
    if (km === null) continue;
    pts.push(`${xOf(hmToMin(t)).toFixed(1)},${yOf(km).toFixed(1)}`);
  }
  if (pts.length < 2) return "";
  return "M" + pts.join(" L");
}

function ariaForTrain(train: StringlineTrain): string {
  const first = train.points[0];
  const last = train.points[train.points.length - 1];
  const dir = train.direction === "down" ? "下り" : "上り";
  return `${train.no} ${KIND_LABEL[train.kind]} ${dir}、${first.station} ${first.scheduled} 発、${last.station} ${last.scheduled} 着のスジ`;
}

// 時刻軸の目盛（10分間隔）
const tickMinutes: number[] = [];
for (let m = Math.ceil(T_MIN / 10) * 10; m <= T_MAX; m += 10) tickMinutes.push(m);
function minToHM(m: number): string {
  const h = Math.floor(m / 60);
  const mm = m % 60;
  return `${String(h).padStart(2, "0")}:${String(mm).padStart(2, "0")}`;
}

export function Stringline() {
  const [selected, setSelected] = React.useState<string | null>(null);

  return (
    <div className="w-full">
      {/* 凡例: Gunjo の Badge を流用（種別の色＝実線、点線＝定刻スジ） */}
      <div className="mb-3 flex flex-wrap items-center gap-2 text-xs text-muted-foreground">
        <Badge variant="destructive">特急</Badge>
        <Badge variant="warning">快速</Badge>
        <Badge variant="info">普通</Badge>
        <span className="ml-1 inline-flex items-center gap-1">
          <svg width="22" height="8" aria-hidden="true">
            <line x1="0" y1="4" x2="22" y2="4" stroke="currentColor" strokeWidth="2" />
          </svg>
          実績スジ
        </span>
        <span className="inline-flex items-center gap-1">
          <svg width="22" height="8" aria-hidden="true">
            <line
              x1="0"
              y1="4"
              x2="22"
              y2="4"
              stroke="currentColor"
              strokeWidth="2"
              strokeDasharray="3 3"
            />
          </svg>
          定刻スジ
        </span>
      </div>

      <div className="w-full overflow-x-auto rounded-md border bg-card">
        <svg
          viewBox={`0 0 ${W} ${H}`}
          className="h-[360px] w-full min-w-[640px]"
          role="img"
          aria-label="彩央本線 運行図表（運行図・スジ）。縦軸は駅（営業キロ）、横軸は時刻。実線が実績、点線が定刻のスジ。"
        >
          {/* 駅（水平グリッド線＋駅名） */}
          {STATIONS.map((st) => {
            const y = yOf(st.km);
            return (
              <g key={st.code}>
                <line
                  x1={PAD_L}
                  y1={y}
                  x2={W - PAD_R}
                  y2={y}
                  stroke="var(--border, #e5e7eb)"
                  strokeWidth={1}
                />
                <text
                  x={PAD_L - 6}
                  y={y}
                  textAnchor="end"
                  dominantBaseline="middle"
                  fontSize={11}
                  fill="var(--muted-foreground, #6b7280)"
                >
                  {st.name}
                </text>
              </g>
            );
          })}

          {/* 時刻（縦グリッド線＋目盛） */}
          {tickMinutes.map((m) => {
            const x = xOf(m);
            return (
              <g key={m}>
                <line
                  x1={x}
                  y1={PAD_T}
                  x2={x}
                  y2={H - PAD_B}
                  stroke="var(--border, #e5e7eb)"
                  strokeWidth={1}
                  strokeOpacity={0.6}
                />
                <text
                  x={x}
                  y={H - PAD_B + 16}
                  textAnchor="middle"
                  fontSize={10}
                  fill="var(--muted-foreground, #6b7280)"
                >
                  {minToHM(m)}
                </text>
              </g>
            );
          })}

          {/* 列車スジ */}
          {stringlineTrains.map((train) => {
            const color = KIND_COLOR[train.kind];
            const isSel = selected === train.no;
            const dim = selected !== null && !isSel;
            const schedPath = pathFor(train, false);
            const actualPath = pathFor(train, true);
            return (
              <g
                key={train.no}
                opacity={dim ? 0.18 : 1}
                style={{ transition: "opacity 120ms" }}
              >
                {/* 定刻スジ（点線） */}
                {schedPath ? (
                  <path
                    d={schedPath}
                    fill="none"
                    stroke={color}
                    strokeWidth={1.5}
                    strokeDasharray="3 3"
                    strokeOpacity={0.7}
                  />
                ) : null}
                {/* 実績スジ（実線・focusable） */}
                {actualPath ? (
                  <path
                    d={actualPath}
                    fill="none"
                    stroke={color}
                    strokeWidth={isSel ? 3.5 : 2.25}
                    strokeLinejoin="round"
                    strokeLinecap="round"
                    tabIndex={0}
                    role="button"
                    aria-label={ariaForTrain(train)}
                    aria-pressed={isSel}
                    style={{ cursor: "pointer", outline: "none" }}
                    onClick={() => setSelected(isSel ? null : train.no)}
                    onKeyDown={(e) => {
                      if (e.key === "Enter" || e.key === " ") {
                        e.preventDefault();
                        setSelected(isSel ? null : train.no);
                      }
                    }}
                  />
                ) : null}
                {/* 始点に列車番号 */}
                {actualPath
                  ? (() => {
                      const p0 = train.points.find((p) => p.actual);
                      if (!p0 || !p0.actual) return null;
                      const km = kmOfStation(p0.station);
                      if (km === null) return null;
                      return (
                        <text
                          x={xOf(hmToMin(p0.actual)) + 4}
                          y={yOf(km) - 4}
                          fontSize={10}
                          fontWeight={600}
                          fill={color}
                        >
                          {train.no}
                        </text>
                      );
                    })()
                  : null}
              </g>
            );
          })}
        </svg>
      </div>
      <p className="mt-2 text-xs text-muted-foreground">
        スジをクリック / Enter で当該列車を強調。点線＝定刻、実線＝実績。傾きが寝るほど低速・停車（抑止）を表す。
      </p>
    </div>
  );
}
